import CountUp from "./CountUp";
const CountUpComponent = () => {
  return (
    <div>
      <div className="flex flex-col items-center justify-center">
      <CountUp
        from={0}
        to={1300}
        separator=","
        direction="up"
        duration={1}
        className="count-up-text"
        delay={0}
      />
      <h2>+ Clients Fidèles</h2>
      </div>
    </div>
  );
};
export default CountUpComponent;
